import{_ as i,o as t,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"3H. Disability Employment Support Officer","description":"","frontmatter":{"title":"3H. Disability Employment Support Officer","eba":"Health Allied & Managers Admin 2021-2025","topics":["schedules","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/schedules/3h-disability-employment-support-officer.md","filePath":"ebas/has-managers-admin/schedules/3h-disability-employment-support-officer.md"}'),s={name:"ebas/has-managers-admin/schedules/3h-disability-employment-support-officer.md"};function n(l,e,r,p,c,m){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_3h-disability-employment-support-officer" tabindex="-1">3H. Disability Employment Support Officer <a class="header-anchor" href="#_3h-disability-employment-support-officer" aria-label="Permalink to &quot;3H. Disability Employment Support Officer&quot;">​</a></h1><p>Formatting note</p><p>The schedule body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find schedules by their title, number, topic or synonyms.</p><p>```text OFFICER 1. The Role 1.1 A Disability Employment Support Officer will be responsible for promoting the achievement of a two per cent Disability Employment Target and the prioritisation of focus areas set out in the DH Disability Employment Strategy 2018-2020: (a) Profile and Leadership (b) Recruitment (c) Induction (d) Inclusive Workplaces (e) Retention</p><ol><li><p>Duties Duties include:</p><p>2.1 Development and/or maintenance of the local Disability Employment Plan which aims to increase the Disability workforce across all areas of the organisation</p><p>2.2 Promote the focus areas set out in the DH Disability Employment Strategy 2018- 2020 and ensure that these practices are culturally relevant, culturally appropriate while also consistent with local policies and procedures.</p><p>2.3 Networking with the local Disability community, Disability community organisations, high schools, TAFE and University.</p></li><li><p>Qualifications/Experience Required qualifications and experience for this role is as follows:</p><p>3.1 Is a person with a disability</p><p>3.2 Evidence of a long-standing commitment to supporting and promoting the individual needs, skills, abilities and personal goals of people with disabilities.</p><p>3.3 Relevant tertiary qualifications in Human Resources (or equivalent) or significant experience in Disability Employment, Recruitment and Engagement. ```</p></li></ol>',5)])])}const u=i(s,[["render",n]]);export{h as __pageData,u as default};
